using LumiBeauty.Api.Data;using LumiBeauty.Api.Services;using Microsoft.AspNetCore.Identity;using Microsoft.EntityFrameworkCore;var builder=WebApplication.CreateBuilder(args);builder.Services.AddControllers();builder.Services.AddScoped<ISmsSender,ConsoleSmsSender>();builder.Services.AddDbContext<AppDbContext>(o=>o.UseSqlServer(builder.Configuration.GetConnectionString("DefaultConnection")));builder.Services.AddIdentity<IdentityUser,IdentityRole>(o=>{o.User.RequireUniqueEmail=true;o.Password.RequiredLength=8;o.Password.RequireDigit=true;o.Password.RequireUppercase=true;o.Password.RequireLowercase=true;o.Password.RequireNonAlphanumeric=false;}).AddEntityFrameworkStores<AppDbContext>().AddDefaultTokenProviders();builder.Services.ConfigureApplicationCookie(o=>{o.Cookie.Name="LumiBeauty.Admin";o.Cookie.HttpOnly=true;o.Cookie.SameSite=SameSiteMode.Lax;o.Cookie.SecurePolicy=CookieSecurePolicy.SameAsRequest;o.Events.OnRedirectToLogin=c=>{c.Response.StatusCode=401;return Task.CompletedTask;};o.Events.OnRedirectToAccessDenied=c=>{c.Response.StatusCode=403;return Task.CompletedTask;};});builder.Services.AddCors(o=>o.AddPolicy("ReactApp",p=>p.WithOrigins("http://localhost:5174","http://127.0.0.1:5174").AllowAnyHeader().AllowAnyMethod().AllowCredentials()));var app=builder.Build();app.UseCors("ReactApp");app.UseAuthentication();app.UseAuthorization();app.MapControllers();await AdminSeeder.SeedAsync(app.Services,app.Configuration);app.Run();
